attempts = {'n': 0}

@retry(times=3, exceptions=(ValueError,))
def flaky():
    attempts['n'] += 1
    if attempts['n'] < 3:
        raise ValueError('not yet')
    return 'ok'

assert flaky() == 'ok'
assert attempts['n'] == 3

# Different exception → should NOT be retried
attempts['n'] = 0
@retry(times=3, exceptions=(ValueError,))
def wrong_exc():
    attempts['n'] += 1
    raise KeyError('no retry for me')

try:
    wrong_exc()
    raise AssertionError('expected KeyError')
except KeyError:
    pass
assert attempts['n'] == 1

